data.content:
Small correction: MSTest doesn't have `Assert.StartsWith`/`Assert.EndsWith`. The string-specific assertions live on the **`StringAssert`** class:

- `StringAssert.StartsWith(string, string)`
- `StringAssert.EndsWith(string, string)`
- `StringAssert.Contains(string, string)`
- `StringAssert.Matches(string, Regex)`

Here's a test class using them:

```csharp
using System.Text.RegularExpressions;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // --- FormatPhoneNumber ---

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");
        StringAssert.StartsWith(result, "(212)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFour()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");
        StringAssert.EndsWith(result, "-1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsExchange()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");
        StringAssert.Contains(result, "555");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesFullPattern()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");
        StringAssert.Matches(result, new Regex(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_Throws()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    public void FormatPhoneNumber_WrongLength_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber("123"));
    }

    // --- BuildGreeting ---

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");
        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");
        StringAssert.EndsWith(result, "Smith,");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_ContainsTitle()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");
        StringAssert.Contains(result, "Dr. Jones");
    }

    [TestMethod]
    public void BuildGreeting_WhitespaceName_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting("   "));
    }

    // --- GenerateSlug ---

    [TestMethod]
    public void GenerateSlug_SimpleTitle_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("Hello World");
        StringAssert.Matches(result, new Regex(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
    }

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsExpected()
    {
        var result = _formatter.GenerateSlug("Hello World");
        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_SpecialChars_DoesNotStartWithHyphen()
    {
        var result = _formatter.GenerateSlug("  ##My Post!!  ");
        StringAssert.DoesNotMatch(result, new Regex(@"^-"));
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceTitle_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug("   "));
    }

    // --- FormatCurrency ---

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollar()
    {
        var result = _formatter.FormatCurrency(9.99m);
        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(9.99m, "€");
        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimals()
    {
        var result = _formatter.FormatCurrency(100m);
        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        var result = _formatter.FormatCurrency(-5.50m);
        StringAssert.Contains(result, "-");
    }
}
```

Key takeaway: **`StringAssert`** is the dedicated class for string checks in MSTest. `Assert` handles general comparisons, nulls, and exceptions — but string pattern matching belongs on `StringAssert`.
